// src/pages/Dashboard.jsx
import React from "react";
import { Link } from "react-router-dom";
import "./Dashboard.css";

export default function Dashboard() {
  // Example: show saved name (optional)
  const userName = localStorage.getItem("userName") || "Student";

  return (
    <div className="dashboard">
      <header className="dashboard-header">
        <h1>🎓 Campus Connect Dashboard</h1>
        <p>Welcome, {userName}!</p>
      </header>

      <nav className="dashboard-nav">
        <Link to="/profile" className="dashboard-link">Profile</Link>
        <Link to="/internship" className="dashboard-link">Internships</Link>
        <Link to="/placement" className="dashboard-link">Placements</Link>
        <Link to="/events" className="dashboard-link">Events</Link>
        <Link to="/notes" className="dashboard-link">Notes</Link>
        <Link to="/notices" className="dashboard-link">Notices</Link>
      </nav>

      <main className="dashboard-main">
        <h2>Your Campus, Connected</h2>
        <p>Select a section to explore resources, updates, and opportunities for your college life.</p>
        <img 
          src="https://img.freepik.com/premium-vector/college-campus-concept-illustration_251005-395.jpg"
          alt="Campus Connect"
          className="dashboard-image"
        />
      </main>
    </div>
  );
}
